<span class="line"><span style="color:#F9E2AF;font-style:italic;">        KeyCode</span><span style="color:#94E2D5;">::</span><span style="color:#89B4FA;font-style:italic;">Char</span><span style="color:#9399B2;">(</span><span style="color:#9399B2;">&#39;</span><span style="color:#A6E3A1;">s</span><span style="color:#9399B2;">&#39;</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> =&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Some</span><span style="color:#9399B2;">(</span><span style="color:#F9E2AF;font-style:italic;">Message</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;font-style:italic;">ToggleSidebar</span><span style="color:#9399B2;">),</span></span>
